class Solution:
    def maxPalindromes(self, s: str, k: int) -> int:
        n = len(s)
        dp = [0] * (n + 1)

        def is_palindrome(i, j):
            while i < j:
                if s[i] != s[j]:
                    return False
                i += 1
                j -= 1
            return True

        for i in range(n):
            for j in range(i + k, n + 1):
                if is_palindrome(i, j - 1):
                    dp[j] = max(dp[j], dp[i] + 1)
            dp[i + 1] = max(dp[i + 1], dp[i])
        return dp[-1]
